// Build a signed POST body for webhook-ai-router.
//
// Signature shape mirrors core/security.py:verify_hmac —
// HMAC-SHA256 of "{timestamp}.{raw_body}" using the shared secret.
// The same raw body bytes that get signed are the ones POSTed.
//
// Configure with the n8n credentials store or, for a quick demo, edit
// the SECRET / TARGET_URL constants below.

const crypto = require('crypto');

const SECRET = process.env.HUBSPOT_WEBHOOK_SECRET || 'ci-test-secret';
const TARGET_URL = process.env.WEBHOOK_ROUTER_URL || 'http://localhost:8000/webhooks/hubspot';

const body = JSON.stringify([
  {
    eventId: Math.floor(Math.random() * 1_000_000),
    subscriptionType: 'contact.creation',
    portalId: 12345,
    objectId: 999,
    occurredAt: Date.now(),
  },
]);

const timestamp = Math.floor(Date.now() / 1000).toString();
const signature = crypto
  .createHmac('sha256', SECRET)
  .update(`${timestamp}.${body}`)
  .digest('hex');
const idempotencyKey = crypto.randomUUID();

return [
  {
    json: {
      target_url: TARGET_URL,
      body,
      timestamp,
      signature,
      idempotency_key: idempotencyKey,
    },
  },
];
